/**
 * ------- UTILIDADES -------
 */

// Converte “29/04/2025 09:00”  ->  “2025-04-29T09:00:00”
const parseBrDate = (s) => {
  if (!s) return null;
  const [d, m, rest] = s.split('/');
  const [y, time]    = rest.trim().split(' ');
  const [hh, mm]     = time.split(':');
  return `${y}-${m.padStart(2,'0')}-${d.padStart(2,'0')}T${hh.padStart(2,'0')}:${mm.padStart(2,'0')}:00`;
};

// Garante formato ISO e coloca “:00” se segundos estiverem ausentes
const cleanDateString = (dateStr) => {
  if (!dateStr) return null;
  dateStr = dateStr.replace(' ', 'T')        // troca espaço por T
                   .replace(/Z$/, '')        // remove Z final
                   .split('.')[0];           // remove milissegundos
  if (dateStr.split(':').length === 2) dateStr += ':00'; // adiciona segundos
  return dateStr;
};

// Soma +1 hora (rodâ 30 => 00)
const addOneHour = (dateStr) => {
  const [datePart, timePart] = dateStr.split('T');
  let [hh, mm, ss] = timePart.split(':').map(Number);

  hh = (hh + 1) % 24;                         // 23+1 → 0
  return `${datePart}T${String(hh).padStart(2,'0')}:${String(mm).padStart(2,'0')}:${String(ss).padStart(2,'0')}`;
};

// Diferença (em horas) entre dois ISO strings (sem ms)
const getHourDifference = (startStr, finishStr) => {
  const start = new Date(startStr);
  const finish = new Date(finishStr);
  return (finish - start) / (1000 * 60 * 60); // ms → h
};

/**
 * ------- PROCESSAMENTO -------
 */

let item = $input.item;

// 1. Pega datas vindas do item (ajuste aqui se seus campos mudarem)
let dateStart  = item.json.data_inicio;   // “2025-04-29 09:00”  ou  “29/04/2025 09:00”
let dateFinish = item.json.data_final;  // idem
let dataAntiga = item.json.data_antiga;  // opcional

// 2. Caso venham no formato BR (dd/mm/aaaa), converte primeiro
if (dateStart?.includes('/') && dateStart?.includes(' '))  dateStart  = parseBrDate(dateStart);
if (dateFinish?.includes('/') && dateFinish?.includes(' ')) dateFinish = parseBrDate(dateFinish);

// 3. Padroniza e garante segundos
dateStart  = cleanDateString(dateStart);
dateFinish = cleanDateString(dateFinish);
dataAntiga = cleanDateString(dataAntiga);

// 4. Se tiver start & finish mas eles NÃO differem 1h → corrige finish
if (dateStart && dateFinish) {
  const diff = getHourDifference(dateStart, dateFinish);
  if (diff !== 1) dateFinish = addOneHour(dateStart);
}

// 5. Escreve de volta no item
item.json.data_inicio  = dateStart;   // 2025-04-29T09:00:00
item.json.data_final = dateFinish;  // 2025-04-29T10:00:00
item.json.data_antiga = dataAntiga;  // se existir

return item;

