function formatHour(date) {
  const pad = n => n.toString().padStart(2, '0');
  return `${pad(date.getHours())}:${pad(date.getMinutes())}`;
}

function formatInterval(start, end) {
  return `${formatHour(start)} às ${formatHour(end)}`;
}

const firstEvent = new Date(items[0].json.start.dateTime);
const year = firstEvent.getFullYear();
const month = firstEvent.getMonth();
const day = firstEvent.getDate();

const workStart = new Date(year, month, day, 8, 0, 0);
const workEnd = new Date(year, month, day, 17, 0, 0);

const busyTimes = items.map(item => ({
  start: new Date(item.json.start.dateTime),
  end: new Date(item.json.end.dateTime)
})).sort((a, b) => a.start - b.start);

let freeSlots = [];
let current = new Date(workStart);

for (let i = 0; i < busyTimes.length; i++) {
  const busy = busyTimes[i];

  if (current < busy.start) {
    const slotStart = new Date(current);
    const slotEnd = new Date(busy.start);

    if (slotStart < workEnd && slotEnd > workStart) {
      freeSlots.push({
        start: slotStart,
        end: slotEnd < workEnd ? slotEnd : new Date(workEnd)
      });
    }
  }

  if (busy.end > current) {
    current = new Date(busy.end);
  }
}

if (current < workEnd) {
  freeSlots.push({
    start: new Date(current),
    end: new Date(workEnd)
  });
}

// Formata os horários disponíveis
const formattedSlots = freeSlots.map(slot => `🕒 ${formatInterval(slot.start, slot.end)}`);
const message = formattedSlots.length
  ? `✅ *Horários disponíveis para agendamento:*\n\n${formattedSlots.join('\n')}`
  : `⚠️ Infelizmente, não há horários disponíveis para agendamento hoje.`;

// Retorna só uma mensagem formatada
return [{ json: { message } }];

const especialidadeBuscada = $('Calcula Datas').first().json.especialidade || '';
const profissionais = $('Busca Todos Profissionais').all().map(i => i.json);

// Função de similaridade
function similaridade(buscado, cadastrado) {
  const a = buscado.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  const b = cadastrado.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

  // Match exato
  if (a === b) return 100;

  // Um contém o outro (cardiologia ↔ cardiologista)
  if (a.includes(b) || b.includes(a)) return 80;

  // Raiz comum (cardio → cardiologista)
  const raizA = a.slice(0, Math.min(5, a.length));
  const raizB = b.slice(0, Math.min(5, b.length));
  if (raizA === raizB) return 70;

  // Começo similar (pelo menos 4 letras)
  if (a.slice(0, 4) === b.slice(0, 4)) return 60;

  return 0;
}

// Encontra o melhor match
let melhorMatch = null;
let melhorScore = 0;

for (const prof of profissionais) {
  if (!prof.especialidade) continue;

  const score = similaridade(especialidadeBuscada, prof.especialidade);
  if (score > melhorScore) {
    melhorScore = score;
    melhorMatch = prof;
  }
}

// Retorna mantendo o pairedItem
const itemOriginal = $input.first();

if (melhorMatch && melhorScore >= 60) {
  return [{
    json: melhorMatch,
    pairedItem: { item: itemOriginal.pairedItem?.item ?? 0 }
  }];
} else {
  return [{ 
    json: { 
      erro: true,
      mensagem: `Especialidade "${especialidadeBuscada}" não encontrada`,
      sugestao: profissionais.map(p => p.especialidade).join(', ')
    },
    pairedItem: { item: itemOriginal.pairedItem?.item ?? 0 }
  }];
}

